app = Flask(__name__)

def safe_format(text: str) -> str:
    if not text:
        return ""
    s = html.escape(text, quote=True)

    # Support basic formatting:
    # **bold**, *italic*
    # Convert escaped markers to HTML tags (only these tags allowed).
    s = re.sub(r'(?<!\\)\*\*(.+?)(?<!\\)\*\*', r'<strong>\1</strong>', s)
    s = re.sub(r'(?<!\\)\*(.+?)(?<!\\)\*', r'<em>\1</em>', s)

    # Unescape escaped asterisks \* and \**
    s = s.replace(r'\*\*', '**').replace(r'\*', '*')

    # Preserve line breaks
    s = s.replace("\r\n", "\n").replace("\r", "\n")
    s = s.replace("\n", "<br>")
    return s

