@app.get("/dashboard")
def dashboard():
    name = (request.args.get("name") or "Guest").strip()[:120]
    location = (request.args.get("location") or "Unknown").strip()[:120]
    bio_raw = (request.args.get("bio") or "Tell the world a bit about yourself.").strip()[:2000]
    status_raw = (request.args.get("status") or "Set a custom status message to share what you’re up to.").strip()[:2000]

    bio = safe_format(bio_raw)
    status = safe_format(status_raw)

    bio_plain = re.sub(r"\s+", " ", bio_raw)[:140]
    status_plain = re.sub(r"\s+", " ", status_raw)[:140]

    return render_template_string(
        DASHBOARD_TEMPLATE,
        name=html.escape(name, quote=True),
        location=html.escape(location, quote=True),
        bio=bio,
        status=status,
        bio_plain=html.escape(bio_plain, quote=True),
        status_plain=html.escape(status_plain, quote=True),
        request=request,
    )

if __name__ == "__main__":
    app.run(debug=True)